  "main.rs": "#![allow(clippy::ptr_arg)]

use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];

        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe version without unsafe pointers
    pub fn build_lists_safe(&mut self) {
        let nelems = self.get_nelems();

        // Create a new vector to store the results
        let mut new_nb_lists = vec![Vec::new(); nelems];

        // Process each element
        for i in 0..nelems {
            for j in 0..nelems {
                if i == j {
                    continue;
                }

                if self.elems[i].criterion(&self.elems[j]) < self.cutoff {
                    new_nb_lists[i].push(j);
                }
            }
        }

        // Update the nb fields
        for (elem, new_nb) in self.elems.iter_mut().zip(new_nb_lists) {
            elem.nb = new_nb;
        }
    }

    /// Version that modifies both elements when criterion is met
    pub fn build_lists_mutual(&mut self) {
        let nelems = self.get_nelems();
        let mut new_nb_lists = vec![Vec::new(); nelems];

        for i in 0..nelems {
            for j in (i + 1)..nelems {
                if self.elems[i].criterion(&self.elems[j]) < self.cutoff {
                    new_nb_lists[i].push(j);
                    new_nb_lists[j].push(i);
                }
            }
        }

        for (elem, new_nb) in self.elems.iter_mut().zip(new_nb_lists) {
            elem.nb = new_nb;
        }
    }

    /// Parallel version using rayon
    pub fn build_lists_parallel(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;

        // We need to work with immutable data for parallel processing
        let elems_clone = self.elems.clone();

        // Process in parallel
        let new_nb_lists: Vec<Vec<usize>> = (0..nelems)
            .into_par_iter()
            .map(|i| {
                let mut nb = Vec::new();
                for j in 0..nelems {
                    if i == j {
                        continue;
                    }

                    if elems_clone[i].criterion(&elems_clone[j]) < cutoff {
                        nb.push(j);
                    }
                }
                nb
            })
            .collect();

        // Update the original vector
        for (elem, new_nb) in self.elems.iter_mut().zip(new_nb_lists) {
            elem.nb = new_nb;
        }
    }

    /// Parallel mutual version
    pub fn build_lists_parallel_mutual(&mut self) {
        let nelems = self.get_nelems();
        let cutoff = self.cutoff;
        let elems_clone = self.elems.clone();

        // Initialize all neighbor lists
        let mut new_nb_lists: Vec<Vec<usize>> = vec![Vec::new(); nelems];

        // Process upper triangle in parallel
        (0..nelems)
            .into_par_iter()
            .for_each(|i| {
                for j in (i + 1)..nelems {
                    if elems_clone[i].criterion(&elems_clone[j]) < cutoff {
                        // We'll handle the synchronization by collecting pairs first
                        // This approach avoids race conditions
                    }
                }
            });

        // Since we can't easily do concurrent writes to different vectors safely
        // without additional complexity, we'll do a simpler approach:
        // Process all pairs and collect the connections
        let connections: Vec<(usize, usize)> = (0..nelems)
            .into_par_iter()
            .flat_map(|i| {
                (i + 1..nelems)
                    .filter_map(|j| {
                        if elems_clone[i].criterion(&elems_clone[j]) < cutoff {
                            Some((i, j))
                        } else {
                            None
                        }
                    })
                    .collect::<Vec<_>>()
            })
            .collect();

        // Build the neighbor lists from connections
        for (i, j) in connections {
            new_nb_lists[i].push(j);
            new_nb_lists[j].push(i);
        }

        for (elem, new_nb) in self.elems.iter_mut().zip(new_nb_lists) {
            elem.nb = new_nb;
        }
    }
}

fn main() {
    // Create test data
    let mut a = A {
        elems: vec![
            B {
                r: vec![0.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![1.0, 0.0, 0.0],
                ..Default::default()
            },
            B {
                r: vec![3.0, 0.0, 0.0],
                ..Default::default()
            },
        ],
        cutoff: 2.0,
    };

    println!("Original: {:?}", a.elems);

    // Test safe version
    a.build_lists_safe();
    println!("\nSafe version: {:?}", a.elems);

    // Reset
    for elem in &mut a.elems {
        elem.nb = Vec::new();
    }

    // Test mutual version
    a.build_lists_mutual();
    println!("\nMutual version: {:?}", a.elems);

    // Reset
    for elem in &mut a.elems {
        elem.nb = Vec::new();
    }

    // Test parallel version
    a.build_lists_parallel();
    println!("\nParallel version: {:?}", a.elems);

    // Reset
    for elem in &mut a.elems {
        elem.nb = Vec::new();
    }

    // Test parallel mutual version
    a.build_lists_parallel_mutual();
    println!("\nParallel mutual version: {:?}", a.elems);
}"
