{
  "Cargo.toml": "rxrust = "1.0.0-rc.2"
",
  "main.rs": "use rxrust::prelude::*;
use std::convert::Infallible;

// Define a type alias for our observables
type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

fn nand(name: String, a: Type, b: Type) -> Type {
    a.combine_latest(b, |a, b| (a, b))
        .distinct()
        .tap(move |(a, b)| print!("nand {} ({}, {})", name, a, b))
        .map(|(a, b)| !(a & b))
        .tap(|v| println!(" = {}", v))
        .box_it_clone()
}

fn flipflop(s: Type, r: Type) -> (Type, Type) {
    // Create shared state using Rc<RefCell<>> to avoid borrowing issues
    let q1_state = Rc::new(RefCell::new(false));
    let q2_state = Rc::new(RefCell::new(false));

    // Create subjects for the feedback paths
    let s2_subject = Local::subject::<bool, Infallible>();
    let r2_subject = Local::subject::<bool, Infallible>();

    let s2_box = s2_subject.clone().box_it_clone();
    let r2_box = r2_subject.clone().box_it_clone();

    // Create the NAND gates
    let q1 = nand("s".to_string(), s, s2_box).box_it_clone();
    let q2 = nand("r".to_string(), r, r2_box).box_it_clone();

    // Subscribe to q1 and feed back to r2
    q1.clone().subscribe({
        let r2_subject = r2_subject.clone();
        let q1_state = q1_state.clone();
        move |value| {
            *q1_state.borrow_mut() = value;
            r2_subject.next(value);
        }
    });

    // Subscribe to q2 and feed back to s2
    q2.clone().subscribe({
        let s2_subject = s2_subject.clone();
        let q2_state = q2_state.clone();
        move |value| {
            *q2_state.borrow_mut() = value;
            s2_subject.next(value);
        }
    });

    // Initialize the feedback with the initial state
    s2_subject.next(*q2_state.borrow());
    r2_subject.next(*q1_state.borrow());

    (q1, q2)
}

use std::rc::Rc;
use std::cell::RefCell;

fn main() {
    let s = Local::behavior_subject::<bool, Infallible>(true);
    let r = Local::behavior_subject::<bool, Infallible>(true);

    let result = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    result
        .0
        .combine_latest(result.1, |q1, q2| (q1, q2))
        .subscribe(|(q1, q2)| println!("({}, {})", q1, q2));

    // Initial state: (s: true, r: true) -> should maintain previous state
    // Since we start with false in feedback, initial output should be (true, true)

    s.next(false); // (s: false, r: true) -> (q1: true, q2: false)
    s.next(true);  // (s: true, r: true) -> (q1: true, q2: false) - holds state

    r.next(false); // (s: true, r: false) -> (q1: false, q2: true)
    r.next(true);  // (s: true, r: true) -> (q1: false, q2: true) - holds state
}"
}

