",
  "main.rs": "use std::fs::OpenOptions;
use tracing::{info, warn, error, Level};
use tracing_subscriber::{
    filter,
    fmt,
    prelude::*,
    reload,
    Registry,
};

fn main() {
    // Open log file
    let file = OpenOptions::new()
        .append(true)
        .create(true)
        .open("logfile.log")
        .expect("Failed to open logfile.log");

    // Create reloadable layers for both console and file
    let (console_layer, console_reload_handle) = reload::Layer::new(
        fmt::layer()
            .compact()
            .with_ansi(true)
            .with_filter(filter::LevelFilter::from_level(Level::INFO))
    );

    let (file_layer, file_reload_handle) = reload::Layer::new(
        fmt::layer()
            .with_ansi(false)
            .with_writer(file)
            .with_filter(filter::LevelFilter::from_level(Level::INFO))
    );

    // Build and set the global subscriber
    let subscriber = Registry::default()
        .with(console_layer)
        .with(file_layer);

    tracing::subscriber::set_global_default(subscriber)
        .expect("Failed to set global default subscriber");

    // Initial logs
    info!("Initial INFO message");
    warn!("Initial WARN message");
    error!("Initial ERROR message");

    // Change only the console layer to ERROR level
    console_reload_handle
        .modify(|layer| {
            *layer.filter_mut() = filter::LevelFilter::from_level(Level::ERROR);
        })
        .expect("Failed to modify console layer");

    println!("\n--- Changed console log level to ERROR ---\n");

    // These will only appear in the file (since console is now ERROR level)
    info!("This INFO message should only appear in the file");
    warn!("This WARN message should only appear in the file");
    error!("This ERROR message appears in both console and file");

    // Optionally, change file layer as well
    file_reload_handle
        .modify(|layer| {
            *layer.filter_mut() = filter::LevelFilter::from_level(Level::WARN);
        })
        .expect("Failed to modify file layer");

    println!("\n--- Changed file log level to WARN ---\n");

    info!("This INFO message should not appear anywhere");
    warn!("This WARN message appears only in the file");
    error!("This ERROR message appears in both");
}"
}

