  "main.rs": "use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};

use serde::Deserialize;
use serde_json::Value;

#[derive(Deserialize, Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

fn resolve_references(
    value: &Value,
    base_path: &Path,
    cache: &mut HashMap<String, Value>,
) -> Result<Value, Box<dyn std::error::Error>> {
    match value {
        Value::Object(map) => {
            if let Some(ref_value) = map.get("$ref") {
                if let Some(ref_str) = ref_value.as_str() {
                    // Check if already resolved
                    if let Some(cached) = cache.get(ref_str) {
                        return Ok(cached.clone());
                    }

                    // Parse the reference: "./a.json#/p_list"
                    let parts: Vec<&str> = ref_str.split('#').collect();
                    if parts.len() != 2 {
                        return Err(format!("Invalid reference format: {}", ref_str).into());
                    }

                    let file_path = parts[0];
                    let json_pointer = parts[1];

                    // Resolve file path relative to base_path
                    let full_file_path = base_path.join(file_path);
                    let file_content = fs::read_to_string(&full_file_path)
                        .map_err(|e| format!("Failed to read referenced file {:?}: {}", full_file_path, e))?;
                    let referenced_json: Value = serde_json::from_str(&file_content)
                        .map_err(|e| format!("Failed to parse referenced file {:?}: {}", full_file_path, e))?;

                    // Navigate using JSON pointer
                    let resolved = navigate_json_pointer(&referenced_json, json_pointer)
                        .ok_or_else(|| format!("JSON pointer not found: {}", json_pointer))?;

                    // Cache the result to avoid re-resolving
                    cache.insert(ref_str.to_string(), resolved.clone());

                    // Recursively resolve any nested references
                    resolve_references(&resolved, &full_file_path.parent().unwrap_or(base_path), cache)
                } else {
                    Err("$ref value must be a string".into())
                }
            } else {
                // Regular object: recursively process all values
                let mut new_map = serde_json::Map::new();
                for (key, val) in map {
                    new_map.insert(
                        key.clone(),
                        resolve_references(val, base_path, cache)?,
                    );
                }
                Ok(Value::Object(new_map))
            }
        }
        Value::Array(arr) => {
            let mut new_arr = Vec::new();
            for item in arr {
                new_arr.push(resolve_references(item, base_path, cache)?);
            }
            Ok(Value::Array(new_arr))
        }
        _ => Ok(value.clone()),
    }
}

fn navigate_json_pointer(value: &Value, pointer: &str) -> Option<Value> {
    if pointer.is_empty() || pointer == "/" {
        return Some(value.clone());
    }

    let tokens: Vec<&str> = pointer
        .trim_start_matches('/')
        .split('/')
        .map(|token| token.replace("~1", "/").replace("~0", "~"))
        .collect();

    let mut current = value;
    for token in tokens {
        current = match current {
            Value::Object(map) => map.get(&token)?,
            Value::Array(arr) => {
                let index: usize = token.parse().ok()?;
                arr.get(index)?
            }
            _ => return None,
        };
    }
    Some(current.clone())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let b_json_path = PathBuf::from("b.json");
    let json_data = fs::read_to_string(&b_json_path)?;
    let json_value: Value = serde_json::from_str(&json_data)?;

    let base_dir = b_json_path.parent().unwrap_or(Path::new("."));
    let mut cache = HashMap::new();
    let resolved_value = resolve_references(&json_value, base_dir, &mut cache)?;

    let a_obj: A = serde_json::from_value(resolved_value)?;

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}
