use std::collections::HashMap;

// Find all imports in a file and rewrite them.
pub fn rewrite_imports(root: &SyntaxNode) -> String {
    let mut edits = HashMap::new();
    for use_item in root.descendants().filter_map(ast::Use::cast) {
        if let Some(use_tree) = use_item.use_tree() {
            rewrite_use_tree(&use_tree, &mut edits);
        }
    }

    // Apply edits to the original source
    let source = root.text().to_string();
    let mut result = source;
    // Sort edits by descending position to avoid offset invalidation
    let mut edit_list: Vec<_> = edits.into_iter().collect();
    edit_list.sort_by_key(|(pos, _)| std::cmp::Reverse(*pos));
    for (pos, (old_len, new_text)) in edit_list {
        result.replace_range(pos..pos + old_len, &new_text);
    }
    result
}

// Rewrite a single `use` tree and its sub-paths
fn rewrite_use_tree(use_tree: &ast::UseTree, edits: &mut HashMap<usize, (usize, String)>) {
    // Handle the current path
    if let Some(path) = use_tree.path() {
        let path_text = path.syntax().text().to_string();
        if path_text.starts_with("vexide::devices") {
            let new_path_str = path_text.replacen("vexide::devices", "vexide", 1);
            let start = path.syntax().text_range().start().into();
            let old_len = path_text.len();
            edits.insert(start, (old_len, new_path_str));
        }
    }

    // Recurse into nested use trees
    if let Some(list) = use_tree.use_tree_list() {
        for child in list.use_trees() {
            rewrite_use_tree(&child, edits);
        }
    }
