[dependencies]
itertools = "0.13"",
  "main.rs": "use itertools::Itertools;

/// Tokenizes a shell command string in a quote-aware fashion.
/// 
/// This function splits the input string into tokens following shell quoting rules:
/// - Single quotes preserve everything inside literally (no escaping)
/// - Whitespace outside quotes acts as token separators
/// - Adjacent non-whitespace characters (including those from quoted and unquoted sections) are joined together
fn tokenize(s: &str) -> Vec<String> {
    s.split("'")
        .enumerate()
        .map(|(i, part)| {
            if i % 2 == 0 {
                // Even index: unquoted section - split by whitespace groups
                part.chars()
                    .group_by(|&c| *c == ' ')
                    .into_iter()
                    .map(|(is_space, chars)| (is_space, chars.collect::<String>()))
                    .collect::<Vec<_>>()
            } else {
                // Odd index: quoted section - treat as single non-space token
                vec![(false, part.to_string())]
            }
        })
        .flatten()
        .group_by(|(is_space, _)| !*is_space)
        .into_iter()
        .map(|(_, group)| {
            group.map(|(_, s)| s).join("")
        })
        .filter(|token| !token.chars().all(|c| c == ' '))
        .collect()
}

fn main() {
    // Test with the example from the problem
    let input = " one  ' two  'three    four";
    let tokens = tokenize(input);

    println!("Input: {:?}", input);
    println!("Tokens: {:?}", tokens);

    // Verify we get exactly 3 tokens as expected
    assert_eq!(tokens.len(), 3);
    assert_eq!(tokens[0], "one");
    assert_eq!(tokens[1], " two  three");
    assert_eq!(tokens[2], "four");

    println!("\nAll tests passed!");
}"
