  "main.rs": "use serde::de::{self, Deserialize, Deserializer, Visitor, MapAccess};
use std::fmt;

#[derive(Debug, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug, Deserialize)]
#[serde(rename_all = "lowercase")]
enum B {
    Foo,
    Bar,
}

struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
        formatter.write_str("struct A")
    }

    fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
    where
        V: MapAccess<'de>,
    {
        let mut x: Option<usize> = None;
        let mut b: Option<Vec<B>> = None;

        while let Some(key) = map.next_key::<String>()? {
            match key.as_str() {
                "x" => {
                    if x.is_some() {
                        return Err(de::Error::duplicate_field("x"));
                    }
                    x = Some(map.next_value()?);
                }
                "b" => {
                    if b.is_some() {
                        return Err(de::Error::duplicate_field("b"));
                    }
                    b = Some(map.next_value()?);
                }
                _ => {
                    // Unknown field, skip it
                    let _ = map.next_value::<de::IgnoredAny>()?;
                }
            }
        }

        let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
        let b = b.unwrap_or_default();

        Ok(A { x, b })
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

fn main() {
    let json = r#"
    {
        "x": 42,
        "b": ["foo", "bar", "foo"]
    }
    "#;

    let a: A = serde_json::from_str(json).expect("Failed to deserialize");
    println!("Deserialized: {:?}", a);

    // Test with extra fields
    let json_with_extra = r#"
    {
        "x": 100,
        "b": ["bar"],
        "extra_field": "ignored"
    }
    "#;

    let a2: A = serde_json::from_str(json_with_extra).expect("Failed to deserialize with extra field");
    println!("Deserialized with extra field: {:?}", a2);
}"
}

