  "main.rs": "use std::fs;
use std::io::Write;

fn load_or_create_file(path: &str) -> Vec<String> {
    match fs::read_to_string(path) {
        Ok(contents) => {
            // If file exists and is readable, parse it
            match serde_json::from_str(&contents) {
                Ok(data) => data,
                Err(_) => {
                    // If parsing fails, start with empty vector
                    Vec::new()
                }
            }
        }
