            // If file doesn't exist or can't be read, create it with empty array
            let initial_data: Vec<String> = Vec::new();
            if let Ok(json) = serde_json::to_string_pretty(&initial_data) {
                let _ = fs::write(path, json);
            }
            initial_data
        }
    }
}

fn save_file(path: &str, data: &Vec<String>) {
    if let Ok(json) = serde_json::to_string_pretty(data) {
