            .map_err(|e| format!("Failed to spawn shell: {}", e))?;

        let (tx, rx): (Sender<String>, Receiver<String>) = unbounded();

        // Clone app handle for reader task
        let app_reader = app.clone();
        let mut session_reader = session.try_clone().map_err(|e| format!("Failed to clone session for reading: {}", e))?;

        // Reader task
        let reader_handle = tokio::spawn(async move {
            let mut buffer = vec![0u8; 1024];
            loop {
                match session_reader.read(&mut buffer).await {
                    Ok(0) => {
                        let _ = app_reader.emit("agent-output", "[process terminated]\r\n");
                        break;
                    }
                    Ok(n) => {
                        let output = String::from_utf8_lossy(&buffer[..n]).to_string();
                        let _ = app_reader.emit("agent-output", output);
                    }
                    Err(e) => {
                        eprintln!("Read error: {}", e);
                        break;
                    }
                }
            }
        });

        // Writer task
        let writer_handle = tokio::spawn(async move {
            while let Ok(message) = rx.recv().await {
                if let Err(e) = session.send_line(&message).await {
                    eprintln!("Write error: {}", e);
                    break;
                }
            }
        });

        // Store sender in app state
        app.manage(Arc::new(Mutex::new(Some(tx))));

        Ok(Self {
            _writer_handle: writer_handle,
            _reader_handle: reader_handle,
        })
    }
}

#[tauri::command]
fn start_agent(app: AppHandle, state: State<'_, AppState>) -> Result<(), String> {
    let agent = Agent::new(app)?;
    *state.agent.lock().unwrap() = Some(agent);
    Ok(())
}

#[tauri::command]
fn send_to_agent(message: String, app: AppHandle) -> Result<(), String> {
    // Retrieve the channel sender from app state
    let tx_option: State<Arc<Mutex<Option<Sender<String>>>>> = app.state();
    let tx_guard = tx_option.lock().unwrap();
    if let Some(tx) = tx_guard.as_ref() {
        tx.send_blocking(message)
            .map_err(|e| format!("Failed to send message: {}", e))?;
        Ok(())
    } else {
        Err("No agent running".into())
    }
}

fn main() {
    tauri::Builder::default()
        .manage(AppState::default())
        .invoke_handler(tauri::generate_handler![start_agent, send_to_agent])
        .setup(|app| {
            // Initialize channel storage
            app.manage(Arc::new(Mutex::new(None::<Sender<String>>)));
            Ok(())
        })
        .run(tauri::generate_context!())
        .expect("error while running tauri application");
}"
}

