  "main.rs": "use std::future::Future;
use std::pin::Pin;
use tokio::sync::mpsc;

pub struct Context(i32);

// Define a trait that represents an async function that can be called once
#[async_trait::async_trait]
pub trait AsyncFnOnce<Args>: Send {
    type Output;
    async fn call_once(self: Box<Self>, args: Args) -> Self::Output;
}

// Implement the trait for any closure that returns a Send future
#[async_trait::async_trait]
impl<F, Fut, Args> AsyncFnOnce<Args> for F
where
    F: FnOnce(Args) -> Fut + Send,
    Fut: Future + Send,
    Fut::Output: Send,
{
    type Output = Fut::Output;

    async fn call_once(self: Box<Self>, args: Args) -> Self::Output {
        (self)(args).await
    }
}

pub enum InnerAsyncEvent {
    DoWithContext {
        block: Box<
            dyn for<'a> Fn(
                &'a mut Context,
            ) -> Pin<Box<dyn Future<Output = ()> + Send + 'a>>
                + Send,
        >,
    },
}

// Helper function to wrap an async closure into the required form
pub fn with_context_async<F>(
    work_sender: &mpsc::UnboundedSender<InnerAsyncEvent>,
    block: F,
) where
    F: for<'a> AsyncFnOnce<(&'a mut Context,)> + 'static,
    F::Output: Send,
{
    let _ = work_sender.send(InnerAsyncEvent::DoWithContext {
        block: Box::new(move |ctx| {
            let boxed_block = Box::new(block);
            Box::pin(async move {
                boxed_block.call_once((ctx,)).await;
            })
        }),
    });
}

#[tokio::main]
async fn main() {
    let (sender, mut receiver) = mpsc::unbounded_channel::<InnerAsyncEvent>();

    // Example usage of the helper function
    with_context_async(&sender, |ctx: &mut Context| async move {
        ctx.0 += 1;
        println!("Context value after increment: {}", ctx.0);
    });

    // Spawn a task to handle the event
    tokio::spawn(async move {
        if let Some(event) = receiver.recv().await {
            let mut ctx = Context(0);
            let fut = match event {
                InnerAsyncEvent::DoWithContext { block } => block(&mut ctx),
            };
            fut.await;
            println!("Final context value: {}", ctx.0);
        }
    }).await.unwrap();
}"
}

