use tracing_opentelemetry::OpenTelemetrySpanExt;

// Mock Pingora-like context that holds the parent span's context
#[derive(Clone)]
pub struct RequestContext {
    // Store the OpenTelemetry context (which includes the span)
    otel_context: Option<Context>,
}

impl RequestContext {
    pub fn new_with_parent_span(span: &Span) -> Self {
        let otel_context = Some(Context::current_with_span(
            span.context().span().clone(),
        ));
        Self { otel_context }
    }

    /// Rehydrate the current tracing context with the stored parent span
    pub fn attach(&self) -> Option<tracing::subscriber::DefaultGuard> {
        if let Some(ctx) = &self.otel_context {
            // Set the OpenTelemetry context as current
            let _guard = ctx.clone().attach();
            // Also set the tracing span as current
            if let Some(span) = ctx.span() {
                return Some(span.set_local_parent());
            }
        }
        None
    }
}

#[async_trait]
trait ProxyStage {
    async fn run_stage(&self, ctx: &RequestContext) -> Result<(), Box<dyn std::error::Error>>;
}

struct Stage1;

#[async_trait]
impl ProxyStage for Stage1 {
    async fn run_stage(&self, ctx: &RequestContext) -> Result<(), Box<dyn std::error::Error>> {
        // Rehydrate the parent span context
        let _guard = ctx.attach();

        // Create a child span for this stage
        let span = tracing::info_span!("stage_1");
        let _enter = span.enter();

        info!("Executing Stage 1");
        tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
        Ok(())
    }
}

