        let _guard = ctx.attach();

        // Create a child span for this stage
        let span = tracing::info_span!("stage_2");
        let _enter = span.enter();

        info!("Executing Stage 2");
        tokio::time::sleep(tokio::time::Duration::from_millis(15)).await;
        Ok(())
    }
}

struct UpstreamCall;

#[async_trait]
impl ProxyStage for UpstreamCall {
    async fn run_stage(&self, ctx: &RequestContext) -> Result<(), Box<dyn std::error::Error>> {
        // Rehydrate the parent span context
        let _guard = ctx.attach();

        // Create a child span for upstream call
        let span = tracing::info_span!("upstream_call");
        let _enter = span.enter();

