struct MyEventHandler {
    insert: String,
}

impl MyEventHandler {
    fn new(insert: char) -> MyEventHandler {
        let insert = String::from(insert);
        MyEventHandler { insert }
    }
}

impl rustyline::ConditionalEventHandler for MyEventHandler {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let line = &line[0..pos];

        // Find the last non-whitespace character before cursor
        if let Some(index) = line.rfind(|c| !char::is_whitespace(c)) {
            if let Some(count) = pos.checked_sub(index + 1) {
                if count > 0 {
                    // We need to delete 'count' whitespace chars and insert our character
                    // The Replace command will replace the movement with the given string
                    // and position the cursor AFTER the inserted text
                    let movement = rustyline::movement::Movement::BackwardChar(count as RepeatCount);
                    return Some(Cmd::Replace(movement, Some(self.insert.clone())));
                }
            }
        }

        // If no whitespace to remove, just insert the character normally
        Some(Cmd::InsertChar(self.insert.chars().next().unwrap()))
    }
}

fn bind_handler(editor: &mut Editor<CommandHelper, DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, Modifiers::NONE);
    let handler = MyEventHandler::new(key);
    let handler = EventHandler::Conditional(Box::new(handler));
