#[derive(Debug)]
pub enum FlusterError {
    FailToParseDate,
}

pub type FlusterResult<T> = Result<T, FlusterError>;

/// Converts a LanceDB ISO date string (with or without fractional seconds) to a Unix timestamp.
/// Handles both formats:
/// - "1970-01-01T00:00:00"
/// - "2025-08-02T17:35:41.409"
pub fn date_string_to_int(d: &str) -> FlusterResult<i64> {
    // Try parsing with fractional seconds first
    if let Ok(dt) = DateTime::parse_from_rfc3339(d) {
        return Ok(dt.timestamp());
    }

    // If that fails, try parsing as naive datetime without timezone
    // and assume UTC
    if let Ok(naive) = NaiveDateTime::parse_from_str(d, "%Y-%m-%dT%H:%M:%S") {
        let dt: DateTime<Utc> = DateTime::from_utc(naive, Utc);
        return Ok(dt.timestamp());
    }

    // Try parsing with up to 9 digits of fractional seconds
    // We'll pad the string with zeros if needed to make it exactly 9 digits
    if d.contains('.') {
        let parts: Vec<&str> = d.split('.').collect();
        if parts.len() == 2 {
            let main_part = parts[0];
            let mut frac_part = parts[1].to_string();

            // Pad fractional part to 9 digits (nanoseconds)
            while frac_part.len() < 9 {
                frac_part.push('0');
            }
            // Truncate to 9 digits if longer
            frac_part.truncate(9);

            let padded = format!("{}.{:09}", main_part, frac_part);
            if let Ok(naive) = NaiveDateTime::parse_from_str(&padded, "%Y-%m-%dT%H:%M:%S%.f") {
                let dt: DateTime<Utc> = DateTime::from_utc(naive, Utc);
                return Ok(dt.timestamp());
            }
        }
    }

    // If all parsing attempts fail, return error
    eprintln!("Date Error: Failed to parse date string: {}", d);
    Err(FlusterError::FailToParseDate)
}

fn main() {
    let test_dates = vec![
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
    ];

    for date_str in test_dates {
        match date_string_to_int(date_str) {
            Ok(timestamp) => println!("Parsed '{}' -> Unix timestamp: {}", date_str, timestamp),
            Err(e) => println!("Failed to parse '{}': {:?}", date_str, e),
        }
    }
}"
}

