  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use futures_util::future::poll_fn;

enum TryPollResult<X> {
    Ready(X),
    Pending,
}

fn try_poll<X>(future: &mut impl Future<Output = X>) -> TryPollResult<X> {
    // Create a no-op waker that does nothing when woken
    let waker = futures_util::task::noop_waker();
    let mut context = Context::from_waker(&waker);

    // Pin the future to the stack so we can poll it
    let mut pinned_future = unsafe { Pin::new_unchecked(future) };

    match pinned_future.as_mut().poll(&mut context) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

// Helper function to demonstrate the usage
async fn immediate_future() -> i32 {
    42
}

async fn delayed_future() -> i32 {
    tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
    100
}

#[tokio::main]
async fn main() {
    println!("Testing immediate future:");
    {
        let mut fut = immediate_future();
        match try_poll(&mut fut) {
            TryPollResult::Ready(value) => {
                println!("Immediate future completed with value: {}", value);
            }
            TryPollResult::Pending => {
                println!("Immediate future was pending (unexpected)");
                // This shouldn't happen for immediate_future
            }
        }
    }

    println!("\nTesting delayed future:");
    {
        let mut fut = delayed_future();
        match try_poll(&mut fut) {
            TryPollResult::Ready(value) => {
                println!("Delayed future completed immediately with value: {}", value);
            }
            TryPollResult::Pending => {
                println!("Delayed future is pending, spawning task...");
                // Spawn a task to await the future
                tokio::spawn(async move {
                    let value = fut.await;
                    println!("Delayed future completed in spawned task with value: {}", value);
                });
            }
        }
    }

    // Wait a bit for the spawned task to complete
    tokio::time::sleep(tokio::time::Duration::from_millis(150)).await;
    println!("\nMain function completed.");
}"
}

