            .await?;
        let client = self.connect(Some(name)).await?;
        client.batch_execute("-- dummy schema").await
    }

    pub async fn drop_database(&self, name: &str) -> Result<u64, tokio_postgres::Error> {
        // Terminate all connections to the target database
        let client = self.connect(None).await?;
        let terminate_sql = format!(
            "SELECT pg_terminate_backend(pid) FROM pg_stat_activity WHERE datname = $1 AND pid <> pg_backend_pid();",
        );
        client.execute(&terminate_sql, &[&name]).await?;

        // Now drop the database
        client.execute(&format!("DROP DATABASE \"{}\"", name), &[]).await
    }

    async fn connect(&self, db_name: Option<&str>) -> Result<Client, tokio_postgres::Error> {
        if let Some(dbname) = db_name {
            // For non-default databases, create a new connection every time
            let conn_str = format!(
                "host=localhost port={} user=postgres password={} dbname={}",
                self.db_config.port, self.db_config.postgres_password, dbname
            );
            let (client, conn) = tokio_postgres::connect(&conn_str, NoTls).await?;

