    pub categories: Option<Vec<serde_json::Value>>,
}

impl ToNotionProperties for MyUnit {
    fn to_notion_properties(&self) -> HashMap<String, PropertyValues> {
        let mut tmp = HashMap::new();

        // Handle 'name' field as title
        tmp.insert(
            "Name".to_string(),
