        // Handle 'icon_url' field as url
        if let Some(ref icon_url) = self.icon_url {
            tmp.insert("Icon url".to_string(), PropertyValues::Url(icon_url.clone()));
        }

        // Handle 'categories' field as multi-select
        if let Some(ref categories) = self.categories {
            let select_objects: Vec<SelectObject> = categories
