use async_std::prelude::*;
use async_std::process::{Child, Command, Stdio};
use async_channel::{unbounded, Receiver, Sender};
use futures::future::FutureExt;
use std::sync::Arc;
use tokio::sync::Mutex;

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Start a child REPL process (using `cat` as a simple echo REPL for demo)
    let mut child = Command::new("cat")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()?;

    let stdin = child.stdin.take().unwrap();
    let stdout = child.stdout.take().unwrap();
    let stderr = child.stderr.take().unwrap();

    let (tx_out, rx_out) = unbounded::<String>();
    let (tx_err, rx_err) = unbounded::<String>();

    // Spawn tasks to read from child's stdout and stderr
    let tx_out_clone = tx_out.clone();
    tokio::spawn(async move {
        let mut lines = BufReader::new(stdout).lines();
        while let Some(line) = lines.next().await {
            if let Ok(line) = line {
                let _ = tx_out_clone.send(line).await;
            }
        }
    });

    tokio::spawn(async move {
        let mut lines = BufReader::new(stderr).lines();
        while let Some(line) = lines.next().await {
            if let Ok(line) = line {
                let _ = tx_err.send(line).await;
            }
        }
    });

    // Shared state for the prompt
    let prompt_state = Arc::new(Mutex::new(PromptState {
        current_prompt: "> ".to_string(),
        pending_output: Vec::new(),
    }));

    // Task to handle output from child
    let prompt_state_clone = prompt_state.clone();
    tokio::spawn(async move {
        let mut outputs: futures::stream::SelectAll<
            futures::stream::BoxStream<'static, String>,
        > = futures::stream::SelectAll::new();
        outputs.push(rx_out.map(|s| s).boxed());
        outputs.push(rx_err.map(|s| s).boxed());

        while let Some(line) = outputs.next().await {
            let mut state = prompt_state_clone.lock().await;
            // Save the current cursor position, clear the line, print output, then restore prompt
            state.pending_output.push(line);
            // We'll handle printing in the main loop
        }
    });

    // Main input loop using tokio's stdin
    let mut input = tokio::io::BufReader::new(tokio::io::stdin());
    let mut buffer = String::new();

    loop {
        // Print any pending output
        {
            let mut state = prompt_state.lock().await;
            for line in state.pending_output.drain(..) {
                // Move cursor up, clear line, print output, then redraw prompt
                print!("\r\x1b[K{}\n", line);
                print!("{}", state.current_prompt);
                std::io::stdout().flush().unwrap();
            }
        }

        // Print prompt if not already printed
        print!("{}", prompt_state.lock().await.current_prompt);
        std::io::stdout().flush().unwrap();

        buffer.clear();
        let bytes_read = input.read_line(&mut buffer).await?;
        if bytes_read == 0 {
            break; // EOF
        }

        let input_line = buffer.trim_end_matches(['\r', '\n']).to_string();
        if input_line == "exit" {
            break;
        }

        // Send input to child process
        use async_std::io::Write;
        let mut stdin = stdin.clone();
        stdin.write_all(format!("{}\n", input_line).as_bytes()).await?;
        stdin.flush().await?;
    }

    // Wait for child to exit
    let _ = child.try_status();
    Ok(())
}

struct PromptState {
    current_prompt: String,
    pending_output: Vec<String>,
}
"
