const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/client/:session_id", get(client_handler));

    let addr = SocketAddr::from(([127, 0, 0, 1], 3000));
    println!("Listening on http://{}", addr);
    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
    headers: axum::http::HeaderMap,
) -> Result<impl IntoResponse, StatusCode> {
    // Extract and validate Origin header
    let origin = headers.typed_get::<Origin>()
        .ok_or(StatusCode::BAD_REQUEST)?;

    let origin_str = origin.to_string();
    if origin_str != ALLOWED_ORIGIN {
        return Err(StatusCode::FORBIDDEN);
    }

    println!("Accepted websocket connection for session: {} from {}", session_id, origin_str);

    Ok(ws.on_upgrade(move |socket| handle_socket(socket, session_id)))
}

