use std::convert::Infallible;
use std::net::SocketAddr;
use std::path::{Path, PathBuf};
use tokio::fs::File;
use tokio_util::io::ReaderStream;

async fn handle_file_request(req: Request<hyper::body::Incoming>) -> Result<Response<hyper::body::Incoming>, Infallible> {
    // Only allow GET requests
    if req.method() != Method::GET {
        let mut resp = Response::new(hyper::body::Incoming::from("Method not allowed"));
        *resp.status_mut() = StatusCode::METHOD_NOT_ALLOWED;
        return Ok(resp);
    }

    // Parse the path from the request URI
    let uri_path = req.uri().path();
    let path = PathBuf::from(".").join(uri_path.trim_start_matches('/'));

    // Normalize the path to prevent directory traversal
    let normalized_path = match normalize_path(&path) {
        Some(p) => p,
        None => {
            let mut resp = Response::new(hyper::body::Incoming::from("Invalid path"));
            *resp.status_mut() = StatusCode::BAD_REQUEST;
            return Ok(resp);
        }
    };

    // Check if it's a file
    let metadata = match tokio::fs::metadata(&normalized_path).await {
        Ok(m) => m,
        Err(_) => {
            let mut resp = Response::new(hyper::body::Incoming::from("Not found"));
            *resp.status_mut() = StatusCode::NOT_FOUND;
            return Ok(resp);
        }
    };

    if !metadata.is_file() {
        let mut resp = Response::new(hyper::body::Incoming::from("Not a file"));
        *resp.status_mut() = StatusCode::NOT_FOUND;
        return Ok(resp);
    }

    // Open the file
    let file = match File::open(&normalized_path).await {
        Ok(f) => f,
        Err(_) => {
            let mut resp = Response::new(hyper::body::Incoming::from("Internal server error"));
            *resp.status_mut() = StatusCode::INTERNAL_SERVER_ERROR;
            return Ok(resp);
        }
    };

    // Create a stream from the file
    let stream = ReaderStream::new(file);
    // Convert the stream to a body that hyper can use
    let body = hyper::body::Incoming::from_stream(stream.map(|result| {
        result.map_err(|e| {
            // Convert io::Error to Box<dyn std::error::Error + Send + Sync>
            Box::new(e) as Box<dyn std::error::Error + Send + Sync>
        })
    }));

    let resp = Response::builder()
        .header("content-length", metadata.len().to_string())
        .body(body)
        .unwrap();

    Ok(resp)
}

// Helper function to prevent directory traversal
fn normalize_path(path: &Path) -> Option<PathBuf> {
    let mut components = path.components().peekable();
    if let Some(first) = components.peek() {
        if first.as_os_str() == ".." || first.as_os_str() == "~" {
            return None;
        }
    }

    let mut normalized = PathBuf::new();
    for component in components {
        match component {
            std::path::Component::ParentDir => {
                if !normalized.pop() {
                    return None;
                }
            }
            std::path::Component::Normal(c) => normalized.push(c),
            std::path::Component::CurDir => {},
            _ => return None,
        }
    }

    Some(normalized)
}

