// We need to implement intersect_ray for Aabb since it's not public in Bevy
trait AabbIntersectRay {
    fn intersect_ray(&self, origin: Vec3, dir: Vec3) -> Option<RayHit>;
}

#[derive(Debug, Clone)]
struct RayHit {
    normal: Vec3,
    distance: f32,
}

impl AabbIntersectRay for Aabb {
    fn intersect_ray(&self, origin: Vec3, dir: Vec3) -> Option<RayHit> {
        let inv_dir = Vec3::new(
            if dir.x.abs() < f32::EPSILON { f32::INFINITY } else { 1.0 / dir.x },
            if dir.y.abs() < f32::EPSILON { f32::INFINITY } else { 1.0 / dir.y },
            if dir.z.abs() < f32::EPSILON { f32::INFINITY } else { 1.0 / dir.z },
        );

        let t_min = (self.center - self.half_extents - origin) * inv_dir;
        let t_max = (self.center + self.half_extents - origin) * inv_dir;

        let t1 = t_min.min(t_max);
        let t2 = t_min.max(t_max);

        let t_near = t1.x.max(t1.y).max(t1.z);
        let t_far = t2.x.min(t2.y).min(t2.z);

        if t_near > 0.0 && t_near <= t_far {
            // Determine which face was hit
            let hit_point = origin + dir * t_near;
            let local_hit = hit_point - self.center;

            let mut normal = Vec3::ZERO;
            let mut max_dot = 0.0;

            // Check each face
            let faces = [
                (Vec3::X, self.half_extents.x),
                (-Vec3::X, self.half_extents.x),
                (Vec3::Y, self.half_extents.y),
                (-Vec3::Y, self.half_extents.y),
                (Vec3::Z, self.half_extents.z),
                (-Vec3::Z, self.half_extents.z),
            ];

            for (face_normal, half_extent) in faces {
                let face_center = self.center + face_normal * half_extent;
                let to_face = face_center - hit_point;
                let dot = face_normal.dot(to_face);
                if dot > max_dot {
                    max_dot = dot;
                    normal = face_normal;
                }
            }

            Some(RayHit {
                normal,
                distance: t_near,
            })
        } else {
            None
        }
    }
}"
}

