use std::sync::Arc;

#[derive(Deserialize, Debug)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// Wrapper that holds both the original string and the deserialized struct
// with proper lifetime management using Arc
struct OwnedMyData {
    // Keep the original string alive
    _json_string: Arc<String>,
    // The deserialized data that borrows from the string
    data: MyData<'static>,
}

impl OwnedMyData {
    fn new(json_string: String) -> Result<Self, serde_json::Error> {
        let json_arc = Arc::new(json_string);

        // SAFETY: We're extending the lifetime of the borrowed data to 'static
        // because we guarantee that the Arc holding the string will live
        // as long as this OwnedMyData instance.
        let data: MyData = unsafe {
            std::mem::transmute::<MyData<'_>, MyData<'static>>(
                serde_json::from_str(json_arc.as_ref())?
            )
        };

        Ok(Self {
            _json_string: json_arc,
            data,
        })
    }

    fn get_data(&self) -> &MyData<'static> {
        &self.data
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let json_input = r#"{"data": "hello", "more_data": "world"}"#.to_string();

    // Deserialize once
    let owned_data = OwnedMyData::new(json_input)?;
    println!("Deserialized in main: {:?}", owned_data.get_data());

    // Clone the Arc wrapper (cheap operation) to send to spawned task
    let owned_data_clone = owned_data.clone();

    let handle = tokio::spawn(async move {
        // Use the deserialized data in the spawned task
        println!("Deserialized in spawned task: {:?}", owned_data_clone.get_data());
        // Do some async work...
        tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
        owned_data_clone.get_data().data.len() + owned_data_clone.get_data().more_data.len()
    });

    let result = handle.await?;
    println!("Total length from spawned task: {}", result);

    Ok(())
}

// Implement Clone for our wrapper
impl Clone for OwnedMyData {
    fn clone(&self) -> Self {
        Self {
            _json_string: Arc::clone(&self._json_string),
            data: self.data, // Copy the struct (which contains 'static references)
        }
    }
}"
