use signal_hook::consts::{SIGINT, SIGTERM};
use signal_hook::iterator::Signals;

#[derive(Debug)]
enum Message {
    Signal(i32),
    Key(char),
    Shutdown,
}

fn yield_signals(sender: Sender<Message>, shutdown_rx: Receiver<()>) {
    let mut signals = Signals::new(&[SIGINT, SIGTERM]).unwrap();

    // We'll use a thread to monitor the shutdown signal
    // and close the signal iterator when needed
    let (sig_sender, sig_receiver) = mpsc::channel();

    // Spawn a thread that waits for either a signal or shutdown
    thread::spawn(move || {
        for sig in signals.forever() {
            if sig_sender.send(Some(sig)).is_err() {
                break;
            }
        }
    });

    loop {
        // Check for shutdown first with a timeout
        let shutdown = match shutdown_rx.recv_timeout(Duration::from_millis(10)) {
            Ok(()) => true,
            Err(_) => false,
        };

        if shutdown {
            break;
        }

        // Check for signal
        if let Ok(Some(sig)) = sig_receiver.try_recv() {
            if sender.send(Message::Signal(sig)).is_err() {
                break;
            }
        }
    }
}

fn yield_keys(sender: Sender<Message>, shutdown_rx: Receiver<()>) {
    let _stdout: Raw-terminal<Stdout> = stdout().into_raw_mode().unwrap();
    let mut stdin = stdin();

    loop {
        // Check for shutdown first
        let shutdown = match shutdown_rx.recv_timeout(Duration::from_millis(10)) {
            Ok(()) => true,
            Err(_) => false,
        };

        if shutdown {
            break;
        }

        // Non-blocking check for input
        if let Ok(event) = stdin.read_event() {
            if let Some(termion::event::Event::Key(Key::Char(key))) = event {
                if sender.send(Message::Key(key)).is_err() {
                    break;
                }
                // Optional: handle 'q' as quit
                if key == 'q' || key == 'Q' {
                    // Send shutdown message to main loop
                    let _ = sender.send(Message::Shutdown);
                }
            }
        }

        // Small delay to prevent busy waiting
        thread::sleep(Duration::from_millis(10));
    }
